import json

# Load all articles knowledge_path = locals().get('var_functions.query_db:2')
articles = []
if isinstance(knowledge_path, str):
    with open(knowledge_path, 'r') as f:
        articles = json.load(f)
else:
    articles = locals().get('var_functions.query_db:2', [])

# Add additional articles from query_db:10
additional_articles = locals().get('var_functions.query_db:10', [])
if isinstance(additional_articles, str):
    with open(additional_articles, 'r') as f:
        articles.extend(json.load(f))
else:
    articles.extend(additional_articles if isinstance(additional_articles, list) else [])

# Also add from query_db:18
approval_articles_path = locals().get('var_functions.query_db:18')
if isinstance(approval_articles_path, str):
    with open(approval_articles_path, 'r') as f:
        articles.extend(json.load(f))
else:
    # Add if it's a list
    approval_articles = locals().get('var_functions.query_db:18', [])
    if isinstance(approval_articles, list):
        articles.extend(approval_articles)

# Find policy articles about quote approval, setup/cost thresholds
policy_keywords = [
    'quote approval', 'approval required', 'approval threshold', 'setup requirements',
    'install', 'installation', 'timeline', 'volume', 'discount limit', 'maximum discount',
    'quote policy', 'pricing policy', 'competing offers'
]

policy_articles = []
for article in articles:
    title = article.get('title', '').lower()
    content = article.get('faq_answer__c', '').lower()

    for keyword in policy_keywords:
        if keyword in title or keyword in content:
            policy_articles.append({
                'id': article.get('id'),
                'title': article.get('title'),
                'content_preview': content[:300]
            })
            break

# Remove duplicates by ID
unique_articles = {}
for art in policy_articles:
    unique_articles[art['id']] = art

print("__RESULT__:")
print(json.dumps(list(unique_articles.values())[:20], indent=2))

